import numpy as np

def lr_grid_search(fn, lrs, n_params, iters=50):
    results = {}
    for lr in lrs:
        x = np.random.randn(n_params)
        for _ in range(iters):
            grad = 2 * x  # For quadratic
            x = x - lr * grad
        results[lr] = fn(x)
    return results

def quadratic(x): return np.sum(x**2)
results = lr_grid_search(quadratic, [0.01, 0.1, 0.5, 1.0], 3)
for lr, val in results.items():
    print(f"lr={lr}: final={val:.6f}")

import numpy as np
from scipy.optimize import minimize

def find_min_depth(energy_fn, max_depth, target):
    for d in range(1, max_depth + 1):
        best = float('inf')
        for _ in range(3):
            x0 = np.random.randn(d * 2) * 0.1
            res = minimize(lambda p: energy_fn(p, d), x0, method='COBYLA', options={'maxiter': 50})
            best = min(best, res.fun)
        if best <= target:
            return d, best
    return max_depth, best

def mock_energy(params, depth): return 1.0 / depth + 0.1*np.random.rand()
depth, energy = find_min_depth(mock_energy, 10, 0.3)
print(f"Depth {depth}, Energy {energy:.4f}")
